DROP TABLE IF EXISTS `lablord_spells`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `lablord_spells` (
  `ls_id` int(20) NOT NULL AUTO_INCREMENT,
  `ls_rules` varchar(10) NOT NULL,
  `ls_name` varchar(100) NOT NULL,
  `ls_reverse` int(1) NOT NULL,
  `ls_class` varchar(20) NOT NULL,
  `ls_level` int(3) NOT NULL,
  `ls_duration` varchar(100) NOT NULL,
  `ls_range` varchar(100) NOT NULL,
  `ls_text` longtext NOT NULL,
  `ls_ref` int(20) NOT NULL,
  PRIMARY KEY (`ls_id`)
) ENGINE=InnoDB AUTO_INCREMENT=162 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

