--
-- Table structure for table `monsters_rpgs`
--

DROP TABLE IF EXISTS `monsters_rpgs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `monsters_rpgs` (
  `id` int(20) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `location` varchar(100) NOT NULL,
  `difficulty` int(3) NOT NULL,
  `turn` int(3) NOT NULL,
  `type` varchar(100) NOT NULL,
  `freq` varchar(100) NOT NULL,
  `enc` varchar(100) NOT NULL,
  `size` varchar(100) NOT NULL,
  `move` varchar(100) DEFAULT NULL,
  `swimmer` int(1) NOT NULL,
  `underground` int(1) NOT NULL,
  `ac` varchar(100) NOT NULL,
  `hd` varchar(100) DEFAULT NULL,
  `atk` varchar(100) NOT NULL,
  `dmg` varchar(100) NOT NULL,
  `spatk` varchar(255) NOT NULL,
  `spdef` varchar(255) NOT NULL,
  `mr` varchar(100) NOT NULL,
  `lair` varchar(100) DEFAULT NULL,
  `iq` varchar(100) DEFAULT NULL,
  `al` varchar(100) DEFAULT NULL,
  `level` varchar(100) NOT NULL,
  `xp` varchar(100) DEFAULT NULL,
  `treasure` longtext,
  `loot` varchar(255) DEFAULT NULL,
  `freq_code` int(2) NOT NULL,
  `creator` varchar(200) NOT NULL,
  `thaco` varchar(100) NOT NULL,
  `weapons` varchar(100) NOT NULL,
  `bravery` varchar(100) DEFAULT NULL,
  `m_trap` int(1) NOT NULL,
  `m_no_dungeon` int(1) NOT NULL,
  `m_app_min` int(5) NOT NULL,
  `m_app_max` int(5) NOT NULL,
  `m_hp_min` int(5) NOT NULL,
  `m_hp_max` int(5) NOT NULL,
  `m_hp_mod` int(5) DEFAULT NULL,
  `m_hoard` int(1) NOT NULL,
  `m_myname` varchar(25) NOT NULL,
  `m_fort` int(1) NOT NULL,
  `m_fort_name` varchar(100) NOT NULL,
  `m_lair` int(1) NOT NULL,
  `description` longtext,
  `salvage` int(5) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=5329 DEFAULT CHARSET=utf8;
/*!40101 SET character_set_client = @saved_cs_client */;

