right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Dryad</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		32-33</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Goblin</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		36-43</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Eagle</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		34-36</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Half-Elf</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		44-46</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Fox</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		37-39</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Halfling</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		47-52</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Hawk</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		40-42</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Half-Orc</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		53-57</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Lynx</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		43-44</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Hobgoblin</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		58-62</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Owl</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		45-88</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Human</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		63-68</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Pixie</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		89-91</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Kobold</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		69-71</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Raccoon</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		92-93</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Ogre</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		72-76</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Faun</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		94-95</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Ogre Mage</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		77-84</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Stag</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		96-98</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Orc</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		85-92</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Wolf</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		99-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Troll</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		93-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Wolverine</td>\r\n	</tr>\r\n	</table></div><br>',0,0),(136,'Repel Insects','Druid',4,'Druidic Abjuration','Abjuration','caster','1 turn/level','one creature','V, S, M','1 round','see below','An invisible barrier forms around the spell\'s recipient  as the caster completes the invocation, warding him or her from insects. Only true insects are affected by the spell, which does not repel spiders, scorpions, beetles or centipedes. Normal insects are completely hedged out by the spell, and giant varieties (2+ HD) must succeed in a saving throw against spells to pass the barrier. Even if a giant insect should manage to penetrate the barrier, it will sustain 1d6 hit points of damage from doing so.',0,0),(137,'Shillelagh','Druid',1,'Druidic Transmutation/Alteration','Transmutation/Alteration','touch','1 round/level','1 oak club','V, S, M','1 segment','none','The druid imbues a club or billet of oak-wood with enchanted power, making it +1 to hit and capable of inflicting 2d4 points of damage against small and medium-sized opponents, 1d4+1 against large opponents. The shillelagh must be wielded by the druid in order for it to possess these magical properties; in the hands of any other person it will be no more than an ordinary wooden club.',0,0),(138,'Snare','Druid',3,'Druidic Enchantment/Charm','Enchantment/Charm','touch','permanent (until triggered)','10 ft radius +6 ft/level','V, S, M','3 rounds','none','This spell is used to enchant a normal snare, making it hard to detect and supernaturally effective. The spell is cast upon a rope, vine, or cord, which then blends perfectly with the surroundings, becoming 90% undetectable to normal (disenchanted) vision. When any creature steps into the area bounded by the snare, the snare will whip closed and bind the victim tightly. Strength of 23 is required to break the snare for one hour after the spell is triggered, and the strength required  falls by one point per hour until 12 hours have elapsed, at which time the spell ceases to have any effect. If the snare is attached to a suitably flexible tree, the spell will magically bend the tree so that when the trap is triggered it will snap the victim into the air for 1d6 points of damage and hold it suspended from the branches.',0,0),(139,'Speak with Animals','Druid',1,'Druidic Transmutation/Alteration','Transmutation/Alteration','0','2 rounds/level','one animal type within 40 ft of the caster','V, S','3 segments','none','This spell allows the druid to speak with all animals of a particular type or species that are within 40 ft of him or her when the spell\'s casting is complete. In all other respects, except as denoted above, the spell is identical to the second level cleric spell speak with animals.',0,65),(140,'Speak with Plants','Druid',4,'Druidic Transmutation/Alteration','Transmutation/Alteration','caster','2 rounds/level','40 ft radius around caster','V, S, M','1 turn','none','Other than as noted above, this spell is identical to the clerical spell speak with plants.',0,68),(141,'Sticks to Snakes','Druid',5,'Druidic Transmutation/Alteration','Transmutation/Alteration','40 ft','2 rounds/level','5 ft radius','V, S, M','7 segments','none','Except as may be noted above, this spell is identical to the clerical spell of the same name.',1,70),(142,'Stone Shape','Druid',3,'Druidic Transmutation/Alteration','Transmutation/Alteration','touch','instantaneous','3 cubic ft +1/level','V, S, M','1 round','none','This spell is identical to the magic user spell of the same name, except as noted above.',0,327),(143,'Summon Insects','Druid',3,'Druidic Conjuration/Summoning','Conjuration/Summoning','30 ft','1 round/level','see below','V, S, M','1 round','none','When the druid completes the intonations and gestures of this spell, a swarm of insects appears from nearby or from the thin air to attack the druid\'s enemies. There is a 70% chance that the swarm will be composed of flying insects, 30% chance that the insects will be ants or other non-airborne biting vermin. A flying swarm can move tremendously fast, but a crawling swarm is limited to movement of 12 ft/round. In either case, the insects automatically inflict 2 hp damage per round against their target, and the unfortunate victim will be so thickly covered as to be incapable of any action, including movement. The druid may redirect the swarm to attack another opponent, but the command will cause 1 round of confusion within  the swarm as it reorients itself toward the new target.',0,0),(144,'Transmute Metal to Wood','Druid',7,'Druidic Transmutation/Alteration','Transmutation/Alteration','80 ft','instantaneous (permanent)','one metal object','V, S, M','9 segments','see below','Using this spell, the druid may select a single object of metal and change its substance to wood. The spell affects up to 8 lbs of metal per level. The item is not entitled  to a saving throw, but magic items have a flat 90% chance of being unaffected by the spell.',0,0),(145,'Transmute Rock to Mud','Druid',5,'Druidic Transmutation/Alteration','Transmutation/Alteration','160 ft','see below','20 cubic ft/level','V, S, M','7 segments','none','This spell transforms solid rock into mud, the volume transformed being proportionate to the caster\'s level. Any volume of mud will sink until its depth is equal to about one half the pool\'s diameter. If this spell is cast upon a ceiling, the resulting volume of mud will immediately  collapse, possibly trapping or suffocating those caught beneath. Similarly, if a floor is turned to mud, creatures standing in the area will sink and may be trapped. If dispel magic  is cast upon the mud before it eventually dries into dirt, the mud will return to stone, but in the shape and location of the mud (i.e., a collapsed ceiling will not return to its original place; it will be frozen back into stone where it collapsed). The spell\'s reverse transforms mud into sandstone or a similar sedimentary rock.',1,0),(146,'Transport via Plants','Druid',6,'Druidic Transmutation/Alteration','Transmutation/Alteration','touch','see below','see below','V, S','3 segments','none','The mystic oneness of all nature is a principal  tenet of many druidic sects, and it sees practical use in the transport via plants spell. Upon casting this spell, the druid  may travel almost instantly from one plant to another through the mystic oneness that joins all life forms. The spell operates in much the same fashion as pass plant, but with an unlimited range. When the spell is cast, the druid simply steps into a large plant of any kind and disappears into it. He or she may remain in the first plant for up to 24 hours, but at any time he or she may step forth from another plant of the same species in another location. The druid may know of a specific plant from which he or she wants to emerge, or may simply specify a distance and a direction. If the druid does not know of a specific destination plant, his or her arrival may be off by 1d% miles from the desired point of arrival, at the GM\'s discretion.\r\n',0,0),(147,'Tree','Druid',3,'Druidic Transmutation/Alteration','Transmutation/Alteration','caster','6 turns +1 turn/level','caster','V, S, M','5 segments','none','Casting this spell causes the druid\'s shape to melt and twist into that of a tree, its general appearance determined by the caster. The spell is neither an illusion  nor a charm: the druid is, for all intents and purposes, a tree. However, in tree shape the druid retains human senses and will be fully aware of his or her surroundings. The druid may shift back into human shape at will, thereby ending the spell. Magical detections will reveal the druid\'s true form, but ordinary inspections, no matter how minute, will not.',0,0),(148,'Trip','Druid',2,'Druidic Enchantment/Charm','Enchantment/Charm','touch','1 turn/level','one object up to 10 ft in length','V, S, M','4 segments','negates','This spell turns an appropriate  object into a magical trap of sorts. The object rises from the ground and trips any creature crossing over it, even if they are aware of it (saving throw vs spells',0,0),(149,'Turn Wood','Druid',6,'Druidic Transmutation/Alteration','Transmutation/Alteration','0','4 rounds/level','120 ft wide path, 20 ft long/level','V, S, M','8 segments','none','At the completion of this spell, the druid holds his or her palm outstretched, and with the final word of the spell a tremendous burst of power rolls forth, forcing back all wooden objects. Even very large wooden structures that are not affixed to the ground will be affected, although objects fixed to the ground will manage to withstand the spell\'s awesome power. A saplingsized or smaller piece of wood will splinter and break even if it is firmly affixed. The druid need not concentrate on maintaining the waves of force and cannot change the direction of the flow of eldritch power once it is set.',0,0),(150,'Wall of Fire','Druid',5,'Druidic Evocation','Evocation','80 ft wall or 80 ft ring around caster','see below','see below','V, S, M','7 segments','none','One of the more dramatic examples of druidic  magic is the wall of fire spell, by which the druid calls up a blazing inferno of flame in the shape of a wall. One side of the conflagration emits the searing heat one would expect, but the other side emits merely a gentle warmth. Passing through the flames inflicts 4d4 damage plus 1/level. Creatures as far as ten ft from the hot side of the wall incur 2d4 hit points of damage, and even creatures as far as 20 ft from the fire are burned for 1d4 points of damage. Undead creatures suffer worse from the power of this druidic magic, taking twice the ordinary  damage the wall would inflict. The wall persists for as long as the druid concentrates upon it, or, if the druid does not choose to maintain concentration, will remain for 1 round/level. The druid may evoke a wall of fire in one of two shapes: a wall or a ring. The size of a straight wall is up to one 20 ft square per level. A ring has a radius of up to five ft per level (with the caster in the center) and is 20 ft high. If the druid manifests the spell as a wall, the effect is stationary. The ring-shaped wall moves with the caster.',0,0),(151,'Wall of Thorns','Druid',6,'Druidic Conjuration/Summoning','Conjuration/Summoning','80 ft','1 turn/level','100 cubic feet/level','V, S','8 segments','none','When the druid casts this spell, a tangled wall of briar vines erupts from the ground, bristling  with sharp, deadly thorns. Running into or attempting to force a way through the thorns will cause 8 hp damage, plus 1 hp for every point of armor class. A creature may be caught within the wall of thorns when the spell is cast, and if this is the case it will take damage immediately and must fight through (taking damage a second time) to gain enough freedom of motion to chop at the thorns. It takes four turns to cut through a 40 ft thickness of a wall of thorns. Normal fire has no effect upon a wall of thorns, but magical fire can ignite the entire growth, creating a wall of fire (as per the spell) that burns away to nothing in two turns.',0,0),(152,'Warp Wood','Druid',2,'Druidic Transmutation/Alteration','Transmutation/Alteration','10 ft/level','instantaneous (permanent)','see below','V, S, M','4 segments','none','This spell permanently warps wood and may be used to destroy arrows, spears, doors, etc. The druid may affect a volume of wood roughly fifteen inches long by one inch thick per level, about the volume of an axe handle. Multiple items may be affected; four arrows have about the same volume as an axe handle. A fifth-level druid could effectively destroy a normal door with this spell.',0,0),(153,'Water Breathing','Druid',3,'Druidic Transmutation/Alteration','Transmutation/Alteration','touch','6 turns/level','one creature','V, S, M','5 segments','none','This spell grants the ability to breathe underwater while the spell lasts. The reverse of the spell allows a water-breathing creature to breathe in the air.',1,0),(154,'Weather Summoning','Druid',6,'Druidic Conjuration/Summoning','Conjuration/Summoning','0','see below','see below','V, S, M','1 turn','none','The area of effect of this spell is d% square miles, but except as noted above, the spell is similar to the clerical spell control weather, allowing the druid to affect, but not direct, existing weather conditions.',0,0),(155,'Affect Normal Fires','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','5 ft/level','1 round/level','1.5 ft radius fire','V, S','1 segment','none','With arcane words and gestures, the magic user may command small fires, up to a limit of 1.5 ft in radius, to grow smaller or larger. Any fire within the spell\'s size limitations may be made as small as a candle flame or turned into a bonfire  up to 3 ft in diameter. An affected fire only consumes fuel appropriate to its new size, but will continue to radiate the same heat as a fire of its original size.',0,0),(156,'Airy Water','Magic-User',5,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','1 turn/level','10 ft radius sphere or 20 ft radius hemishpere','V, S, M','5 segments','none','This spell transforms water or other non-magical liquids into a bubble of air in the area surrounding the caster. The bubble has the same density as water and will not support the magic user in the water; he or she will sink or float as normal, surrounded by the bubble\'s atmosphere. The oxygen content of the air in the bubble does not run out until the spell expires.',0,0),(157,'Animal Growth','Magic-User',5,'Arcane Transmutation/Alteration','Transmutation/Alteration','60 ft','1 round/level','up to 8 animals in a 20 ft square area','V, S','5 segments','none','Other than as noted above, this spell is identical to the druidic spell animal growth.',0,78),(158,'Animate Dead','Magic-User',5,'Arcane Necromancy','Necromancy','10 ft','permanent','see below','V, S, M','5 rounds','none','Other than as noted above, this spell is identical to the clerical spell animate dead.',0,2),(159,'Anti-Magic Shell','Magic-User',6,'Arcane Abjuration','Abjuration','caster','1 turn/level','5 ft radius/level globe','V, S','1 segment','none','An anti-magic shell is a bubble  of space around the magic user that completely prevents all magic from operating within its confines. Spell effects do not enter or function within  the shell, providing the caster with complete protection from gaze attacks, hostile spells, and even the entrance of conjured  or summoned creatures into his or her vicinity. The drawback of an anti-magic shell, of course, is that the caster him or herself cannot cast spells or avail him or herself of magic items while inside. Magic weapons, armor, and the like do not gain their bonuses or abilities while inside the shell, but would still function as non-magical weapons or armor.',0,0),(160,'Antipathy/Sympathy','Magic-User',8,'Arcane Enchantment/Charm','Enchantment/Charm','30 ft','12 turns/level','10 cubic ft/level or a single object','V, S, M','6 turns','see below','This spell affects an area or an object with a magical aura that repels or attracts a certain, specified type of being. Either a race of creature or an alignment must be specified. Note that if the spell is cast upon an object rather than an area, the targeted type of creature will have a penalty of -2 on the saving throw. If the magic user creates an antipathy for the area or object, the targeted creature type will feel an intense desire to stay away from it. A saving throw applies, permitting the creature to remain, or to touch the object, but even if the saving throw is successful the creature will feel extremely uncomfortable in its presence. Creatures that are able to remain in the area or near the object will begin to lose 1 point of dexterity per round (maximum 4 points) from discomfort. If the magic user creates sympathy for an object or area, on the other hand, the targeted creature type will feel attracted to the area or object, pleased to remain in the vicinity, or covetous of the \"precious\" item. If the creature does not make a saving throw, it will do whatever is in its power to stay in contact with the area or the enchanted object.',0,0),(161,'Astral Spell','Magic-User',9,'Arcane Evocation','Evocation','touch','see below','see below','V, S','9 segments','none','Other than as described above, this spell is identical to the clerical spell of the same name.',0,4),(162,'Audible Glamor','Magic-User',2,'Arcane Illusion/Phantasm','Illusion/Phantasm','60 ft +10 ft/level','2 rounds/level','hearing distance from targeted point','V, M','2 segments','see below','This spell is, as its name suggests, the creation of illusory sounds. The caster designates a focal point for the spell, which must, of course, be within  the spell\'s range. The focal point can be moved by the caster at will until the spell\'s duration expires. The spell can create any type of sound, but the maximum volume of the noise depends upon the caster\'s level. A third level caster can produce the noise of 4 people shouting (or acting more quietly). Each additional level allows the caster to add the sound of four more people into the illusion. As a benchmark, the sound of an explosion or landslide would require a level of approximately 8th. Listeners are only entitled  to saving throws if they have cause to doubt the apparent sounds. Players must state such disbelief, while the GM will make such determinations for monsters and NPCs based on the plausibility of the audible glamor.',0,0),(163,'Blink','Magic-User',3,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','1 round/level','caster','V, S','1 segment','none','This spell is a weak and rather unreliable  form of one of the true mage\'s most powerful capabilities: teleportation magic. For the duration of the spell, the magic user teleports 2 ft in a random direction once per round. The segment in which the magic user disappears and reappears is determined on 2d4, while the compass direction is rolled on a d8. If the direction roll would result in the caster being teleported into a solid object, the caster will blink a second time, for a distance of no more than 10 ft. If this second blink also results in the caster occupying a solid object, the spell will end, marooning  the caster in the ethereal plane of existence. During and after the segment in which the teleportation occurs, the magic user\'s sudden change of location prevents any direct attacks upon him or her. The caster may only be attacked directly if the attack is made before the blink takes place. If the caster teleports both from and into an area which is affected by an area of effect spell, he will suffer its effects. The constant changes of location take a toll upon the caster, who has a 25% chance of failing at attempts to cast spells, use most magic items, or take any action beyond making physical attacks.',0,0),(164,'Burning Hands','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','1 round','fan of ?ame 3 ft long in a 120 degree arc','V, S','1 segment','none','While casting this spell, the magic user touches his or her thumbs together, and a sheet of flame explodes from his or her fingers to burn opponents  within  the spell\'s short (3 ft) range. The flames inflict  1 hp of damage per level (no saving throw applies). Any combustible items caught in the sheet of flame must pass a saving throw against normal fire or be destroyed.',0,0),(165,'Cacodemon','Magic-User',7,'Arcane Conjuration/Summoning','Conjuration/Summoning','10 ft','see below','one summoned creature','V, S, M','5 hours','see below','This spell summons a demon or other fiend (such as a devil) from the lower planes of existence into the material planes. In order to cast the spell, the caster must know the fiend\'s true name, but such information is often contained in forbidden tomes of lost lore. The spell cannot summon the lesser sorts of demons that have no personal names, nor is it powerful enough to summon members of the demonic or diabolical nobility. The spell provides no protection whatsoever against the wrath of the summoned creature',0,0),(166,'Charm Monster','Magic-User',4,'Arcane Enchantment/Charm','Enchantment/Charm','60 ft','see below','see below','V, S','4 segments','negates','This spell operates as charm  person does, but can affect any living creature; possibly more than one, depending  on the monsters\' level value. See the chart below:\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Level Value</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Number</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Chance/Week to</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		<b>of Monsters</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		<b>Affected</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		<b>Break Enchantment</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		2d4</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		5%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 2</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1d4</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		10%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 3</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1d2</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		15%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 4</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		25%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 5</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		35%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 6</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		45%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 7</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		60%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 8</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		75%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Level 9+</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		90%</td>\r\n	</tr>\r\n</table></div><br>',0,0),(167,'Charm Person','Magic-User',1,'Arcane Enchantment/Charm','Enchantment/Charm','120 ft','see below','one person','V, S','1 segment','negates','The powerful enchantment woven by this spell will affect any \"person,\" meaning character races (but note that elves are 90% resistant), and humanoids (as defined in Chapter V) up to a ceiling of one hit die of charmed creatures per character level at any one time. If the target creature fails a saving throw, it will view the magic user as a trusted friend, interpreting his or her every word in its most positive light. Charmed creatures will place themselves into moderate danger, including combat, on the caster\'s behalf, but will not undertake risks beyond those the creature might ordinarily take. The magic user must be able to talk to the charmed creature if he or she is to give it any sort of complex \"request.\" Charmed creatures are allowed periodic  saving throws to break the charm, based on intelligence:\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		19+</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/day</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		18</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/2 days</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		17</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/3 days</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		15-16</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/week</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		13-14</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/2 weeks</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		10-12</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/3 weeks</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		7-9</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/month</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		4-6</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/2 months</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" valign=\"top\">\r\n		3 or less</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		one saving throw/3 months</td>\r\n	</tr>\r\n</table></div><br>\r\nThe charm will be broken automatically if the magic user obviously tries to harm the charmed creature.',0,0),(168,'Charm Plants','Magic-User',7,'Arcane Enchantment/Charm','Enchantment/Charm','30 ft','permanent','30 x 10 ft','V, S, M','1 turn','negates','This spell grants the magic user the ability to communicate with (for a period of 1 turn) and command plants (the obedience is permanent) in the spell\'s area of effect. No unusual abilities are granted to the plants; they have no additional capabilities beyond those they had before the spell was cast. Only intelligent plants are entitled to a saving throw, but at a penalty of -4.',0,0),(169,'Clairaudience','Magic-User',3,'Arcane Divination','Divination','see below','1 round/level','see below','V, S, M','3 segments','none','Clairaudience allows the caster to eavesdrop magically upon a particular location. There is no effective limit to the spell\'s range, but the location must either be familiar to the caster or be obvious, such as the top floor inside a tower the caster can see, or just beyond a dungeon door. The spell cannot penetrate metal; sheets of any type of metal between the caster and the target area will prevent the magic user from being able to scry upon the area. The caster will be able to hear sounds in a 6 ft radius of the spell\'s focal point. The spell cannot be used to scry across planes of existence; it is limited to locations in the same plane in which it is cast.',0,0),(170,'Clairvoyance','Magic-User',3,'Arcane Divination','Divination','see below','1 round/level','see below','V, S, M','3 segments','none','Clairvoyance, together with clairaudience, is one of the classic \"scrying\" spells',0,0),(171,'Clenched Fist','Magic-User',8,'Arcane Evocation','Evocation','5 ft/level','1 round/level','enchanted hand','V, S, M','8 segments','none','As with the other hand spells, clenched fist evokes a magical hand, but in this case the hand is always at least as large as a giant\'s and is curled into a fist rather than held open. The clenched fist strikes one of the magic user\'s enemies per round, never missing, for so long as the caster concentrates upon it. No other activity is possible while concentrating, and breaking the caster\'s concentration ends the spell. The fist rolls a d20 to determine damage (it hits automatically): on a roll of 1-12, the fist deals 1d6 hp of damage; on a 13-15, it deals 2d6 hit points, on a roll of 16-19 it deals 3d6 hit points and stuns the opponent for one round, and on a roll of 20 + it deals 4d6 hit points and stuns the opponent for 3 rounds. If the opponent has already been stunned, the d20 roll receives a +4 bonus. As with the other hand spells, the hand has as many hit points as the caster\'s full hit points.',0,0),(172,'Clone','Magic-User',8,'Arcane Necromancy','Necromancy','touch','instantaneous','one clone','V, S, M','1 turn (see below)','none','This eerie spell creates a true, living duplicate of a creature, grown in a vat in the magic user\'s laboratory and matured rapidly to adulthood. The clone has the level, the experience points, and the memories of the original person as of the time a piece of that person was obtained for the purpose of making a clone. If a clone and its original  exist simultaneously, the magical flux of such a situation can drive either or both of them insane. Each will seek to destroy the other with an uncontrollable sense that something is horribly wrong while both exist. If the situation persists, the clone is 70% likely to go insane, a\r\n20% chance that the original will go insane, and a 5% chance that both will become insane, with a 5% chance that both will somehow accept that they co-exist. It takes 2d4 months for the caster to grow the clone in his vats before it becomes a true duplicate of the original. If the process of vat-growth is interrupted prematurely, the clone will be utterly insane, hating all living things, and may become psychotic.',0,0),(173,'Cloudkill','Magic-User',5,'Arcane Evocation','Evocation','10 ft','1 round/level','cloud 40 ft wide, 20 ft high, 20 ft deep','V, S','5 segments','see below','This spell calls into being a poisonous cloud of roiling vapor, heavier than air, which moves along the ground (or into holes) at a movement rate of 10 ft/round. The eldritch poison of the cloud is so virulent that it kills creatures of fewer than 4+1 HD instantly, with no saving throw. Creatures with 4+1 HD up to\r\n5+1 HD are allowed a saving throw at 4, and creatures of 5+2 up to 6 HD must make a normal saving throw. Failure on the saving throw means that the victim dies. The spell is affected normally by winds, although it magically avoids rolling  back over the caster under any circumstances. It is dispersed in 4 rounds by a strong wind, and by thick growths of vegetation if it rolls through these for a distance of 20 ft.',0,0),(174,'Comprehend Languages','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','5 round/level','one written object or one creature','V, S, M','1 round','none','This spell allows the magic user to decipher a written language (including pictographs, but not including magical script), or to understand the speech of another creature. The spell does not permit the magic user to understand the \"speech\" of animals; only true, spoken languages can be understood.  The caster gains no ability to speak or write the language, only to comprehend meaning. The spell\'s reverse makes a particular creature or piece of writing  indecipherable, or may be used to cancel the effects of a comprehend languages spell.',1,0),(175,'Cone of Cold','Magic-User',5,'Arcane Evocation','Evocation','0','instantaneous','cone 5 ft long/level, 1 ft radius at base/level','V, S, M','5 segments','half','A cone of cold  is a blast of magical cold originating from the caster\'s outstretched hand. The cone inflicts 1d4+1 hit points per level of the caster. All unprotected items in the area of effect may be destroyed if they fail item saving throws.',0,0),(176,'Confusion','Magic-User',4,'Arcane Enchantment/Charm','Enchantment/Charm','120 ft','2 rounds +1 round/level','up to 60 x 60 ft','V, S, M','4 segments','see below','This spell affects a base number of 2-16 creatures, but is otherwise identical to the druidic spell of the same name except as noted in the summary information above.',0,91),(177,'Conjure Elemental','Magic-User',5,'Arcane Conjuration/Summoning','Conjuration/Summoning','60 ft','1 turn/level','elemental creature','V, S, M','1 turn ','none','By means of this spell, the magic user calls an elemental being from the plane of air, fire, earth or water to do his or her bidding. The particular form of elemental to be summoned is a part of the spell\'s incantation, so the magic user must memorise the spell for a particular element. The magic user exerts control over the elemental by concentrating upon it, and if his or her concentration is broken by being damaged or grabbed, he or she will lose control  of the elemental. The magic user\'s ability to control the elemental is limited to 30 ft. There is a 1 in 20 chance per round after the second round that the elemental will break free of the magic user\'s control  even if the magic user is concentrating upon maintaining it. If the elemental breaks free of the magic user\'s control or if the magic user ceases to concentrate upon it, it will seek to attack the magic user as soon as it can finish any combat in which it is involved. A magic user can, of course, avail him or herself of protections against an elemental such as the use of a magic circle or a protection from evil spell. The material component for this spell is a large quantity of the appropriate elemental substance.',0,0),(178,'Contact Other Plane','Magic-User',5,'Arcane Divination','Divination','caster','see below','caster','V','1 turn','none','The caster divorces his or her mind from the rational reality of the material plane, accepting the fundamental contradictions of extra-planar realities, and making contact with the powers of the beyond. By means of this contact, he or she can query the powers and gain \"yes or no\" answers to the questions he or she poses. One question may be asked per 2 levels. The caster decides how deeply he or she wishes to probe into the realities beyond the material (unless he or she chooses to contact an elemental plane for information about that plane). The difficulty of the mental task is measured in terms of how many fundamental contradictions of reality the caster can assimilate and simultaneously juggle in his or her mind. The price of failure is insanity. Contacting an elemental plane provides a 90% chance that the being contacted will have the knowledge the magic user seeks, if the magic user is asking about the particular elemental plane. There is a 25% chance that the being will tell a lie, or that the information will be couched in such inherently contradictory language that it cannot be understood. If the magic user seeks information about the material plane or non-elemental planes, he or she must delve into the fundamental contradictions of extra-planar metaphysics, described on the following table:<br><br>Column 1: Number of fundamental metaphysical contradictions (selected by the caster).<br><br>Column 2: Likelihood that the knowledge is available at this level of metaphysical abstraction.<br><br>Column 3: Likelihood that the interpretation of the information gleans the wrong result.<br><br>Column 4: Chance of insanity (reduced by 5% per point of intelligence over 15).<br>\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Column 1</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Column 2</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Column 3</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Column 4</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		60%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		35%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		5%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		2</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		65%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		33%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		10%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		3</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		70%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		30%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		15%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		4</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		75%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		27%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		20%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		5</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		80%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		25%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		25%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		6</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		85%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		22%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		30%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		7</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		90%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		19%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		35%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		8</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		95%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		15%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		40%</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		9</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		98%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		10%</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		50%</td>\r\n	</tr>\r\n</table></div><br>\r\nIf the caster is driven insane by what he or she finds or by simple cognitive breakdown, the insanity will last 1-10 weeks, and there is a 1% chance that the caster will die or commit suicide at the end of this period if it is not removed (by a remove curse spell, wish, etc.).',0,0),(179,'Continual Light','Magic-User',2,'Arcane Transmutation/Alteration','Transmutation/Alteration','60 ft','permanent','60 ft radius sphere','V, S','2 segments','see below','This spell brings into being a bright, magical illumination almost sufficient to rival the light of day. In all respects, the spell is identical to the first level cleric spell light, but its effects are permanent until dispelled. The light cast is greater than that produced  by a light spell, extending 60 ft into the darkness. The magic user spell cannot be used to create continual darkness.',0,0),(180,'Control Weather','Magic-User',6,'Arcane Transmutation/Alteration','Transmutation/Alteration','0','4d6 hours','4d4 square miles','V, S, M','1 turn','none','Except as may be noted above, this spell is identical to the clerical spell control weather.',0,14),(181,'Crushing Hand','Magic-User',9,'Arcane Evocation','Evocation','5 ft/level','1 round/level','see below','V, S, M','9 segments','none','This spell calls into existence a large, floating hand much like that summoned by the other hand spells. The crushing hand attacks any foe the caster directs, grabbing it and squeezing with great power. Damage increases as the hand continues to constrict, doing 1d10 points of damage in the first round, 2d10 points of damage in the second and third  round, and 4d10 points of damage per round thereafter. As with the other hand spells, the hand has as many hit points as its caster. The caster cannot engage in any other activity while directing the hand.',0,0),(182,'Dancing Lights','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','40 ft + 10 ft/level','2 rounds/level','see below','V, S, M','1 segment','none','This spell creates small lights at a chosen distance, under the caster\'s control. The magic user may create 1-4 (at his or her option)  torch-like  lights, 1-4 (at his or her option)  spherical lights, or a single, faintly human-like glow. The lights move at the caster\'s mental command, without any particular concentration required. If the magic user allows the lights to move beyond the spell\'s range, the lights will disappear and the spell will end.',0,0),(183,'Darkness (15 ft radius)','Magic-User',2,'Arcane Transmutation/Alteration','Transmutation/Alteration','10 ft/level','1 turn +1 round/level','15 ft radius sphere','V, M','2 segments','see below','This spell creates an area of utter darkness that prevents all natural vision, even infravision. The spell\'s effect is neutralized by (and neutralizes) the counteracting effect of a light or continual light spell.',0,0),(184,'Death Spell','Magic-User',6,'Arcane Necromancy','Necromancy','10 ft/level','instantaneous','5 x 5 ft/level','V, S, M','6 segments','none','Within its limit as to hit dice, this spell slays living creatures in the area of effect. Creatures of 9 or higher hit dice are not affected. The spell kills 4d20 \"points\" worth of creatures, where (for the purposes of this spell) any creature of fewer than 2 HD counts as one point, creatures of 2 to less than 4 HD count as 4 points, creatures of 4 to less than 7 HD count as 8 points, and creatures from 7 to less than 9 HD count as 10 points. Creatures of the lowest hit dice die first, and fractional \"kills\" (where insufficient points remain completely to slay the creature) have no effect. Material components for the spell cost 1,000 gp.',0,0),(185,'Vision','Illusionist',7,'Phantasmal Divination','Divination','caster','see below','caster','V, S, M','7 segments','none','By means of this spell, the illusionist gazes beyond reality itself, seeking patterns that will give him or her the answer to a question. 3d6 are rolled, and if the result is 10 or higher, he or she gains significant insights about the answer to the question. Gazing into the patterns beyond reality is a risky proposition, however; if the result of the die roll is from 2-6, the illusionist becomes obsessed with performing a task, and is treated as being under a geas spell until the random task is completed. If the roll is from 7-9 there is no result at all from the divination; the illusionist discerns no useful patterns, and suffers no ill effects from the attempt.',0,0),(186,'Wall of Fog','Illusionist',1,'Phantasmal Transmutation/Alteration','Transmutation/Alteration','30 ft','2d4 rounds +1 round/level','20 cubic ft/level','V, S, M','1 segment','none','The illusionist creates a curtain of obscuring fog in the area of effect. Vision of all kinds is reduced to 2 ft through the swirling vapor. The fog can be affected by normal or magical wind and breezes.',0,0),(187,'True Sight','Illusionist',6,'Phantasmal Divination','Divination','touch','1 round/level','60 ft','V, S','3 segments','none','This spell is identical in function (other than as may be noted above) to the clerical spell true seeing, except that the illusionist cannot discern alignments, for this spell is not of a spiritual nature.',0,0),(188,'Veil','Illusionist',6,'Phantasmal Illusion','Illusion','10 ft/level','1 turn/level','20 x 20 ft/level','V, S','3 segments','none','Veil is an extremely powerful spell of the same type as hallucinatory terrain, which alters the appearance of an area and everything in it, including people and other creatures. The illusion will fool even the sense of touch.',0,0),(189,'Summon Shadow','Illusionist',5,'Phantasmal Conjuration/Summoning','Conjuration/Summoning','10 ft','1 round +1 round/level','summoned shadows','V, S, M','5 segments','none','This spell summons 1 undead shadow per level from the shadow planes. The shadows are under the illusionist\'s command and will do his or her bidding. If turned, they will return to the shadow plane whence they came.',0,0),(190,'Spectral Force','Illusionist',3,'Phantasmal Illusion','Illusion','60 ft +10 ft/level','see below','40 x 40 ft square +(10 x 10 ft square)/level','V, S, M','3 segments','see below','This spell functions  in the same manner as improved phantasmal  force, but it is a more powerful evocation of the same magic. The illusionist can include sounds, smells, and heat (or cold) into the illusion, making it very believable. The spectral force can linger for 3 rounds after the illusionist ceases to concentrate upon it.',0,0),(191,'Delayed Blast Fireball','Magic-User',7,'Arcane Evocation','Evocation','100 ft +10 ft/level','see below','20 ft radius sphere','V, S, M','7 segments','half','A delayed blast fireball is somewhat more powerful than a normal fireball (+1 damage on each die). At the time of casting, the magic user states an amount of time, from 1 segment (6 seconds) to 5 rounds (5 minutes), and the fireball will not explode until that time is reached. Otherwise, except as noted above, the spell functions as per the description of the fireball spell.',0,0),(192,'Detect Evil','Magic-User',2,'Arcane Divination','Divination','caster','5 rounds/level','path 10 ft wide, 60 ft long','V, S','2 segments','none','This spell allows the magic user to detect emanations of evil (or good, in the case of the spell\'s reverse) within  the spell\'s area of effect, a beam-like pathway. The spell detects evil, not danger, so it will be useless to discover such things as a mindless trap or a poisoned wineglass. Neither will it detect a cursed item unless the nature of the curse is such that the cursed item becomes inherently evil.',1,0),(193,'Detect Invisibility','Magic-User',2,'Arcane Divination','Divination','caster','5 rounds/level','path 10 ft wide, 10 ft long/level','V, S, M','2 segments','none','This spell allows the caster to see that which is invisible or hidden, and also to perceive the astral and ethereal planes. The spell\'s sight is limited to the stated range of 10 ft/level.',0,0),(194,'Detect Magic','Magic-User',1,'Arcane Divination','Divination','caster','2 rounds/level','path 10 ft wide, 60 ft long','V, S','1 segment','none','Other than as noted above, this spell functions  in the same manner as the clerical spell detect magic.',0,25),(195,'Dig','Magic-User',4,'Arcane Evocation','Evocation','30 ft','1 round/level','5 cubic ft/level','V, S, M','4 segments','none','This spell causes dirt to begin piling out from the ground, digging a hole with tremendous speed. The excavation proceeds at a rate of one 5 x 5 ft cube per round, as earth boils out of the area the caster directs, landing to the edges of the pit. If the spell is cast directly beneath a creature, the creature will fall in without any possibility  of a saving throw. Creatures at the edge of the pit have some likelihood of falling in; they must roll lower than their dexterity score on a d20 to avoid sliding into the sudden maelstrom of moving earth. A creature moving toward the pit during the first round in which digging begins must make a saving throw vs spells (unlisted categories) or fall into the hole. The spell can be used to excavate in dirt, sand, or mud. Note that if the pit is taken deeper than 5 ft, there is a chance that it will collapse in on itself (roughly 25%, adjusted by the GM for the type of material being dug).',0,0),(196,'Dimension Door','Magic-User',4,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','see below','caster','V','1 segment','none','Dimension door is a weak form of teleportation, more controllable than blink, but severely limited in range. The teleportation is limited to 30 ft per level. Unlike blink, a dimension door spell operates with perfect accuracy, either to a place the caster can see or clearly visualize, or in response to directions (example: \"120 ft forward and 30 ft to the right\"). If the caster\'s directions land him or her inside a solid object, he or she is stunned and trapped in the astral plane, held in a sort of suspended animation for eternity unless rescued. The spell is subject to a maximum weight limit of 500 lbs of additional weight, with each lb of living matter counting for twice its actual weight. Recovery from the experience of this form of teleportation is not immediate, although it is quite rapid. The caster cannot act for a period of 6 segments following the transition.',0,0),(197,'Disintegrate','Magic-User',6,'Arcane Transmutation/Alteration','Transmutation/Alteration','5 ft/level','instantaneous','see below','V, S, M','6 segments','negates','This spell disintegrates matter of any kind: animal, vegetable, or mineral. Matter of a magical nature will also be destroyed, although evocations of magic force (such as a wall of force, globe of invulnerability, or shield) are not affected (not being matter). An entire creature, or an area of non-living matter up to 10 x 10 ft/level, will be utterly obliterated by this powerful spell. The spell cannot be used to destroy both living and nonliving matter; once it hits its first target it will take effect upon that matter and not pass beyond.',0,0),(198,'Dispel Magic','Magic-User',3,'Arcane Abjuration','Abjuration','120 ft','permanent','30 cubic ft','V, S','3 segments','none','Except as noted above, this spell is identical to the clerical spell dispel magic.\r\n',0,27),(199,'Distance Distortion','Magic-User',5,'Arcane Transmutation/Alteration','Transmutation/Alteration','10 ft/level','1 turn/level','100 square ft/level','V, S, M','6 segments','none','This spell is cast with a summoned earth elemental as its focus. The casting of the spell is fascinating to summoned elementals and is sufficient  to maintain the caster\'s control  over the elemental (although he or she cannot command it to act while in the process of casting). When the casting is completed, the earth elemental disperses into the substance of the earth as directed, where it creates a dimensional distortion of the spell\'s area of effect. Travel through the distorted area takes twice as long (and seems twice as far) as it should, or seems half as long and takes half the normal travel time (determined by the caster when casting the spell). The area does radiate magic, slightly, and the reality will be perceived by true seeing (although the travel time will still be altered even for those who know that the distance is distorted).  Otherwise, the spell is utterly undetectable. Otherwise, the spell is utterly undetectable.',0,0),(200,'Duo-Dimension','Magic-User',7,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','3 rounds +1/level','caster','V, S, M','7 segments','none','By means of this spell, the caster reduces him or herself to a two-dimensional sheet with no third dimension. He or she can fit through the thinnest of spaces provided they are large enough to accommodate his or her remaining  two dimensions he or she cannot bend down while two-dimensional. Moreover, he or she can become invisible by the simple expedient of turning sideways. While two-dimensional, the caster can move, cast spells, and otherwise act normally. If attacked from the front or back, however, he or she takes three times normal damage. Casting the spell requires expensive material components of (1d4+4)x1,000 gp in value.',0,0),(201,'Enchant an Item','Magic-User',6,'Arcane Conjuration/Summoning','Conjuration/Summoning','touch','see below','one item','V, S, M','1d8+2 days','see below','This spell is the culminating moment involved in the creation of a true magic item, when the item is actually infused with the magic properties  it has been painstakingly prepared to hold. Before the spell can actually be cast, the magic user must engage in considerable time-consuming and meticulous work, or the spell will certainly fail. Firstly, the item itself must be of absolutely the finest quality available, in terms of craftsmanship, although it need not necessarily be fancy. In most cases, special components such as powders or threads will be incorporated into the item\'s construction, costing not less than 100 gp. The casting of the spell takes 1d8 +2 days, with the caster working  steadily upon the item for eight hours per day. No other spells may be cast during this period of time, nor can the magic user engage in any other meaningful  work. When the final words of the spell are spoken, the item makes a saving throw against spells at the same level as the magic user, but with success on the saving throw indicating that the spell has succeeded. A natural result of 1 on this roll always indicates failure of the spell. At this point, the magic user may begin to infuse the item with enchantments, each of which requires 5d8 hours to complete. Most magic items will require unusual components; dragon scales or blood for a sword with an unusually high bonus against dragons, for example. The GM will determine  exactly what is required  for any particular magic item. This spell is not permanent unless a permanency spell is cast upon it; the duration of the enchantment may be for a year or more without a permanency spell, but the enchantment  will eventually fail if it is not locked in to the item.',0,0),(202,'Enchanted Weapon','Magic-User',4,'Arcane Transmutation/Alteration','Transmutation/Alteration','touch','5 rounds/level','see below','V, S, M','1 turn','none','With a touch of his or her hand, the magic user creates a weak and temporary enchantment  upon a full-sized  weapon, or upon two smaller weapons such as arrows, bolts, or daggers. The enchantment  lends no bonus to hit, but may be used to strike creatures that can be hit only with a magical weapon. When the weapon hits successfully, the enchantment ends.',1,0),(203,'Enlarge','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','5 ft/level','1 turn/level','one creature or object','V, S, M','1 segment','negates','This spell causes a creature or object to grow in size and weight. The spell increases a creature\'s size and weight by 20% for each level of the caster (to a maximum increase of 200%) or increases an object\'s size and weight by 10% per level (to a maximum increase of 100%). The magic user\'s power limits the volume of material that he or she can enlarge; the mage can affect no more than 10 cubic ft of living matter, or 5 cubic ft of non-living matter, per level. A normal sized person doubled in size will generally have strength of 18, and tripled in size would have strength of 20+. The spell\'s reverse applies in the same ratios, but with the effect of reducing the size of an object or creature. If the spell is cast on an unwilling recipient, a successful saving throw will negate the spell, but willing recipients may choose to forgo the save.',1,0),(204,'Erase','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','30 ft','instantaneous','scroll or two pages of writing','V, S','1 segment','see below','This spell may be used to erase normal or magical writing from an area about two pages wide. The base chance to erase a magical writing is 50% + 2%/level, and the base chance to erase non-magical writing is 50% + 4%/level. Obviously, the main benefit of this spell is that the erasure can be made at a distance. The spell does not remove such magical rune-traps as symbol, glyph of warding or explosive runes (exception:  the caster may use it to remove such spells if he or she originally cast them him or herself).',0,0),(205,'ESP','Magic-User',2,'Arcane Divination','Divination','caster','1 round/level','5 ft radius/level (maximum of 90 ft)','V, S, M','2 segments','none','This spell allows the caster to overhear the surface thoughts of any thinking being in the spell\'s radial area of effect. The caster need not be able to see the creature whose thoughts he is reading; the spell can be used to listen beyond a closed door. The spell cannot penetrate more than two ft of stone or more than two inches of any metal, and it is foiled by even a thin sheet of lead.',0,0),(206,'Explosive Runes','Magic-User',3,'Arcane Transmutation/Alteration','Transmutation/Alteration','touch','permanent (until triggered)','one object','V, S','3 segments','see below','This spell creates a magical trap in the form of traceries and sigils placed upon a piece of writing that create a magical detonation when they are read. It is possible to detect the presence of explosive runes without detonating them: a magic user has a 5% chance per level to notice their presence, and a thief has a 1% chance per level. When the runes are read, the resulting explosion causes 6d4+6 points of damage (half with a successful saving throw) to any creature within a 10 ft radius. The reader of the runes does not receive a saving throw. The caster and any other magic user with whom the caster has made familiar the secret pattern of the runes can read the protected document or tome without danger, and the caster can erase them at will. Otherwise, only a dispel magic  or similar enchantment will remove the runes before they are triggered. Note that the item upon which the runes are scribed, if it is not resistant to fire, will undoubtedly be destroyed when the runes detonate.',0,0),(207,'Extension I','Magic-User',4,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','see below','see below','V','2 segments','none','The arcane words of an extension I spell act to lengthen the duration of another spell previously cast by the magic user by 50%. The previous spell must still be active and may only be of level 1, 2, or 3.',0,0),(208,'Extension II','Magic-User',5,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','see below','see below','V','4 segments','none','The arcane words of an extension II spell act to lengthen the duration of another spell previously cast by the magic user by 50%. The previous spell must still be active and may only be of level 1, 2, 3, or 4.',0,0),(209,'Extension III','Magic-User',6,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','see below','see below','V','5 segments','none','The arcane words of an extension III spell act to lengthen the duration of another spell previously cast by the magic user by 50%. The previous spell must still be active and may only be of level 4 or 5. It doubles the duration of spells level 1-3.',0,0),(210,'False Trap','Magic-User',2,'Arcane Illusion/Phantasm','Illusion/Phantasm','touch','permanent','one object','V, S, M','3 rounds','none','By means of this spell, the mage weaves an illusion  around an object, making it appear trapped to any normal inspection (such as by a thief). Any such examiner has an 80% chance of finding and believing the false trap. This likelihood decreases by 3% per level of experience of the thief. Furthermore, if a thief attempts to remove the illusory trap, believing it to be real, there is only a 20% likelihood that the illusion will be dispelled or exposed by these efforts. In this case, the thief, seeing the illusion  unchanged, will usually conclude that the attempt to remove the \"trap\" has failed. Only one false trap may be placed within a 50 ft radius, and if two items bearing this illusion come within 50 ft of each other, both will be dispelled.',0,0),(211,'Fear','Magic-User',4,'Arcane Illusion/Phantasm','Illusion/Phantasm','0','see below','cone (60 ft long, 5 ft at origin, 30 ft at terminu','V, S, M','4 segments','negates','This spell causes utter panic in the creatures exposed to the cone-shaped emanation of phantasmal terror the caster hurls forth. If any creature, of any level or hit dice, fails its saving throw against the spell, it will bolt away from the caster as fast as possible for as many rounds as the caster\'s level. There is a base 60% chance for a creature to drop whatever it is holding (immediately  upon failing the saving throw), reduced by 5% per HD or level of the panicked creature.',0,0),(212,'Feather Fall','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','10 ft/level','1 segment/level','10 cubic ft','V, M','less than a segment','none','This spell causes creatures or objects in the area of effect to fall as slowly and lightly as feathers, at a rate of about 10 ft in six seconds (1 segment). No damage is taken from the distance spent falling under the influence of the spell, but it is worthy of note that if the spell\'s target has not landed by the time the spell expires, the fall will resume at normal speed and damage will be taken for the remaining distance. The magic user can affect a weight of up to 200 lbs plus another 200 lbs/level. The spell may be used to slow propelled objects such as arrows, but will not affect sword blows or other non-propelled forces.',0,0),(213,'Feeblemind','Magic-User',5,'Arcane Enchantment/Charm','Enchantment/Charm','10 ft/level','permanent','one creature','V, S, M','5 segments','negates','Except as may be noted above, this spell is identical to the druidic spell feeblemind.',0,108),(214,'Feign Death','Magic-User',3,'Arcane Necromancy','Necromancy','touch','6 rounds +1 round/level','one creature','V, S','1 segment','none (willing recipient only)','This spell magically slows the recipient\'s  metabolism into a state so close to death that it is impossible to distinguish the enspelled person from a corpse by any means other than magical. The recipient  can hear, smell, and think; the senses of touch and sight no longer function.  Damage caused to the pseudocorpse is reduced by one half, and the spell\'s recipient will not even know that the damage has been caused potentially a dangerous situation. A person under the influence of this spell is not subject to level draining by the undead and will not be affected by poisons until the spell wears off or is otherwise removed; the caster can remove the catalepsy at will, and the spell is subject to being dispelled.',0,0),(215,'Find Familiar','Magic-User',1,'Arcane Conjuration/Summoning','Conjuration/Summoning','0','see below','1 mile radius/level','V, S, M','2d12 hours','see below','Magic users of higher level often summon familiars to assist them with various tasks. Indeed, a familiar can also be of considerable benefit to a lower level magic user (even increasing others\' estimation of his or her power), but the risks inherent in losing a familiar can be daunting to a weaker spell caster. To summon a familiar, the magic user must intone the words of the spell over a well-stocked fire source, sprinkling the flames with expensive incense and powders (100 gp in total value). The caster must maintain his or her casting for as long as necessary (2d12 hours) until a familiar arrives (or the casting time expires without success). The spell may be attempted only once per year, and the caster has no control over the type of animal that will respond. When it arrives, the familiar is a faithful servant and ally to the caster. Normal familiars have 1d3+1 hit points, are AC 7, and are as intelligent as a lower-than-average human. When the familiar is within 120 ft of the magic user, the magic user gains additional hit points equal to the familiar\'s. However, if the familiar is ever killed, the magic user permanently loses twice the familiar\'s hit points.\r\n\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>1-2</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>3-5</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>6-8</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>9-11</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>12-14</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>15+</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; \" align=\"center\">\r\n		<b>Familiar</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		01-05</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		01-05</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		01-06</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		01-06</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		01-07</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		01-07</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Special</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-wi