dth: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		30-41</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		34-45</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		34-46</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Hawk</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		36-45</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		37-47</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		41-51</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		42-53</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		46-57</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		47-59</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Owl</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		46-55</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		48-58</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		52-52</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		54-65</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		58-69</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		60-72</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Raven</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		56-65</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		59-69</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		63-73</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		66-77</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		70-81</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		73-85</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Toad</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		66-75</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		70-80</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		74-84</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		79-89</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		82-93</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		86-98</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		Weasel</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		76-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		81-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		85-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		90-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		94-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		99-00</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		None</td>\r\n	</tr>\r\n</table></div><br>\r\n\r\nA special familiar is entitled to a saving throw in order to avoid the effect of the spell. The type of special familiar to appear depends upon the magic user\'s alignment:\r\n\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Lawful Good or Lawful Neutral:</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Brownie</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Chaotic Good, Neutral Good, or Neutral:</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Pseudo-Dragon</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Lawful Evil or Neutral Evil:</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Imp</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Chaotic Evil or Chaotic Neutral:</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Quasit</td>\r\n	</tr>\r\n</table></div><br>',0,0),(216,'Fire Charm','Magic-User',4,'Arcane Enchantment/Charm','Enchantment/Charm','10 ft','2 rounds/level','15 ft radius around fire','V, S, M','4 segments','negates','This spell transforms an existing fire into a powerful mental snare. Any creature within the spell\'s radius who even so much as glances at the fire must make a saving throw vs spells or be entranced by the dancing flames. While so entranced, the creature becomes susceptible to the caster\'s words, in the same manner as with a suggestion spell, but with a penalty of -3 to the saving throw. The enchantment will be broken if the entranced creature can no longer see the flames or if it is attacked.',0,0),(217,'Fire Shield','Magic-User',4,'Arcane Evocation','Evocation','caster','2 rounds +1 round/level','caster','V, S, M','4 segments','none','Pale flames envelope the caster upon the completion of this spell, rendering  him or her protection against either fire or cold based attacks, depending upon whether  the magic user elects to wreath him or herself in cold flame or hot flame. Cold flame grants the magic user a +2 bonus on any saving throw vs fire damage, also guaranteeing half damage (or no damage against all fire attacks that allow a saving throw for half damage) provided the saving throw is successful. If the magic user fails a saving throw against a cold based attack, however, he or she will suffer twice the normal damage. Hot flame offers the converse of the protections afforded by cold flame. Cold based attacks receive a bonus of +2 on saving throws and guarantee that the caster receives only half damage (or none at all) if his or her saving throw is successful against attacks that would cause full or half damage.',0,0),(218,'Fire Trap','Magic-User',4,'Arcane Evocation','Evocation','touch','permanent (until triggered)','one object','V, S, M','3 rounds','half','This spell enchants any item that can be opened or closed with a magical trap. When the item is opened by any person other than the caster, magical fire explodes in an area five ft in radius around the fire trapped object, causing 1d4 plus the caster\'s level hit points of damage to all creatures in this area. A successful saving throw indicates half damage. The item upon which this spell is cast suffers no damage from the explosion. Detecting a fire trap is extraordinarily difficult; attempts to find traps are reduced by one-half in efficacy if the trap is a fire trap, and the trap will detonate if an attempt to remove traps fails.',0,0),(219,'Fireball','Magic-User',3,'Arcane Evocation','Evocation','100 ft +10 ft/level','instantaneous','20 ft radius sphere','V, S, M','3 segments','half','With a pointing gesture at the ending of the incantation, the magic user causes a massive explosion of magical fire at the target point. The fireball  detonates with a low roar, causing\r\n1d6 damage per level to all creatures within  the area\r\nof effect. Creatures making successful saving throws suffer only half the indicated damage. When the magic user casts the spell, a bead of light streaks from his or her pointed finger to the target area, and if it strikes another object directly in its path the fireball  will detonate immediately. The blast fills the entire volume of the spell radius, and if it is cast into an enclosed area smaller than the area of effect the flames will expand from this area until the spell\'s full volume has been reached. The volume of a 20 ft radius sphere is approximately\r\n33,500 cubic ft, and there are 1,000 cubic ft in a 10 x 10 x 10 ft area, so in an area with a 10 ft ceiling the fireball  will fill approximately  thirty-three 10 x 10 ft squares. Thus, if a fireball explodes in the middle of a corridor 10 ft wide and 10 ft high, the blast will extend a staggering 165 ft in both directions. It is quite possible, particularly  in dungeoneering environments, for the magic user to be caught in the backblast of his or her own fireball  spell. The flames do not create any significant change in air pressure, but the furnace-like  heat causes all items in the blast to make saving throws against magical fire or ignite (or, in the case of metals, melt).\r\n',0,0),(220,'Flame Arrow','Magic-User',3,'Arcane Evocation','Evocation','touch','1 segment/level','arrows or bolts','V, S, M','3 segments','none','By means of this spell, the magic user may enchant one arrow per segment, causing it to burst into normal flame. The enchanted arrows have no bonus to hit, and the enchantment is not powerful enough to hit a creature that can be damaged only by magical weapons. Each arrow causes 1 hp of fire damage in addition to its normal damage. The arrows (or crossbow bolts) will burn up in one round, so they must be shot before this time.',0,0),(221,'Floating Disk','Magic-User',1,'Arcane Evocation','Evocation','20 ft','3 turns +1 turn/level','see below','V, S, M','1 segment','none','This evocation produces an invisible disk about three ft across, shaped like a shallow bowl. The disk floats in the air and moves in accordance with the caster\'s commands (although if it is allowed more than 20 ft from the caster it will disappear). The disk cannot move faster than 60 ft per round. A floating disk can carry up to 100 lbs per level of the caster.',0,0),(222,'Fly','Magic-User',3,'Arcane Transmutation/Alteration','Transmutation/Alteration','touch','6 turns/level +1d6 turns','one creature','V, S, M','3 segments','none','This spell grants the power of flight with aerial agility level V (see Chapter III) to any creature the magic user touches. The base movement rate for flight is 120 ft per round, with the base speed being doubled when diving, halved when climbing. The GM secretly rolls a 1d6 to determine how much time the spell will last after the base duration expires.',0,0),(223,'Fool\'s Gold','Magic-User',2,'Arcane Transmutation/Alteration','Transmutation/Alteration','10 ft','6 turns/level','1 cubic ft/level','V, S, M','1 round','see below','This spell achieves the much sought-after goal of transmuting copper or brass into gold. Regrettably, the effect is temporary, but an amoral caster might seek to shift the consequent feelings of regret onto another person than him or herself. Whatever motives drive the caster, he or she may use this spell to transmute roughly 2,000 copper coins (about a cubic foot) per level into a metal that closely resembles gold. Anyone viewing this metal has a chance to notice that it is not truly gold. If the result of d20 plus the caster\'s level is equal to or less than the observer\'s intelligence, the fraud is detected (the GM may pick a representative number for creatures whose exact intelligence is not known, or roll a die). By combining expensive material components with the spell, the caster can make it more likely that the gold will seem true',0,0),(224,'Forceful Hand','Magic-User',6,'Arcane Evocation','Evocation','10 ft/level','1 round/level','see below','V, S, M','6 segments','none','This spell creates a powerful,  magical hand similar to that of the magic user spell interposing hand. Unlike the interposing hand, the forceful hand can push opponents or objects. The hand can move a creature weighing 500 lbs or less. It reduces the speed of a creature between 500 and 2,000 lbs to no greater than 10 ft /round, and it slows the movement of creatures heavier than 2,000 lbs but smaller than 8,000 lbs to one-half. As in the case of the interposing hand, the forceful hand has as many hit points as the caster.',0,0),(225,'Forget','Magic-User',2,'Arcane Enchantment/Charm','Enchantment/Charm','30 ft','instantaneous (permanent)','1-4 creatures in a 20 ft square area','V, S, M','2 segments','negates','This extremely potent spell causes the victims to forget events of the immediate past. The spell obliterates memory of the last round plus one additional round per three levels. The caster decides which creatures in the spell\'s area to affect, and these must make saving throws or suffer the loss of memory. The caster may designate 14 creatures as the targets of the spell. If one is targeted, the saving throw is made with a -2 penalty; if two are targeted, the penalty is -1; and if 3 or 4 creatures are targeted they suffer no penalty to the saving throw. Lost memories can only be restored by heal, restoration, or wish; the spell\'s effect is not subject to being merely dispelled.',0,0),(226,'Freezing Sphere','Magic-User',6,'Arcane Transmutation/Alteration','Transmutation/Alteration','see below','see below','see below','V, S, M','6 segments','see below','This spell may be employed in one of three different forms, depending upon the words and material component used during casting. At the time of memorization, the magic user need not specify which will be used; these are alternate uses of the same spell, not different versions of it.\r\n\r\nIce seed:  conjures a sphere of an intensely cold magical substance that freezes water to a depth of 6 inches over a surface area 100 square ft/level. The ice is thick enough to walk upon without fear of falling through. The duration of the ice is\r\n1 round/level. The material component for this use is a piece of crystal.\r\n\r\nIce ray:  a ray of cold lances from the caster\'s hand, inflicting 4 hp/level against anything in its path. A successful saving throw results in no damage. Even if the ray strikes an object, it continues on the other side until it has extended 10 ft/level or is stopped by a thickness of stone of 1 ft or more. The material component for this use is a gem worth 1,000 gp.\r\n\r\nShattering globe: the spell forms a globe one inch in diameter, cold but not uncomfortable to the touch. When this sphere is thrown (by hand or sling), it will explode upon impact for 4d6 hit points of damage within a 10 ft radius (half if save vs spells). If not used within  1 round/level, it will explode at the time its duration ends. The material component for this use is also a gem worth 1,000 gp.',0,0),(227,'Friends','Magic-User',1,'Arcane Enchantment/Charm','Enchantment/Charm','caster','1 round/level','10 ft radius +10 ft/level','V, S, M','1 segment','see below','This spell increases the magic user\'s charisma in the eyes of all creatures within  the area of effect that fail saving throws. For these creatures, the magic user\'s charisma will effectively be increased by 2d4 (one roll for all). For those who succeed in making the saving throw, the caster\'s charisma will effectively be lowered by 1d4. Unless the exact numbers are required for some purpose, the normal result of the spell will be that those who failed the saving throw will be well-disposed  and friendly  toward the caster, and those that succeeded in making the save will find him or her distasteful and somewhat suspect.',0,0),(228,'Fumble','Magic-User',4,'Arcane Enchantment/Charm','Enchantment/Charm','10 ft/level','1 round/level','one creature','V, S, M','4 segments','half','This enchantment  causes intense clumsiness in the affected creature. Attempting to run will result in an immediate fall to a prone position, and anything held in hand (or claw, etc.) will be dropped. A successful saving throw allows the affected creature to act as if under the influence of a slow  spell in order to avoid the spell\'s full effects.',0,0),(229,'Gate','Magic-User',9,'Arcane Conjuration/Summoning','Conjuration/Summoning','30 ft','see below','one summoned creature','V, S','9 segments','none','A gate spell creates an opening between the material plane and another plane of existence, summoning forth a being from the other plane. The caster must know the name of the creature he or she is attempting  to summon, or the spell will fail. The particular creature named in the spell\'s casting might choose not to step through  the gate  into the material plane',0,0),(230,'Geas','Magic-User',6,'Arcane Enchantment/Charm','Enchantment/Charm','touch','see below','one creature','V, S','4 segments','none','A geas is a magical compulsion placed upon an intelligent creature to perform,  or refrain from performing, some task set by the caster. While the geas cannot compel suicide or its equivalent, it is a very powerful spell. If the creature under the geas avoids or is prevented from performing the task, it will sicken and die within 1d4 weeks if the task is not resumed. The disease will, of course, create symptoms that the GM will determine; if the geas is resumed, these may or may not remain until the task is completed. Even a remove curse spell will not remove a geas, although a wish spell is powerful enough to dispel it.',0,0),(231,'Glass-Steel','Magic-User',8,'Arcane Transmutation/Alteration','Transmutation/Alteration','touch','permanent','one object','V, S, M','8 segments','none','This spell grants a glass object the strength of steel, while retaining its transparent properties.  The weight of the object can be no more than 10 lbs per level. In most cases, the object will make item saving throws on the more favorable of the glass or metal tables.',0,0),(232,'Glasseye','Magic-User',6,'Arcane Transmutation/Alteration','Transmutation/Alteration','touch','1 round/level','see below','V, S, M','1 round','none','This spell causes opaque materials to become transparent, either to the caster alone or to anyone, at the caster\'s option. The dimensions of the transparent area are 3 x 2 ft, and the depth depends upon the nature of the substance being made transparent. Lead and gold, being the base and pure metals respectively, are not affected by the spell at all. Only four inches of any other metal can be made transparent, but stone can be seen through  to a distance of 6 ft, and wood to a distance of 20 ft.',0,0),(233,'Globe of Invulnerability','Magic-User',6,'Arcane Abjuration','Abjuration','0','1 round/level','5 ft radius sphere','V, S, M','1 round','none','This spell creates a spherical shield, impermeable to spells. It functions as the spell minor globe of invulnerability except as noted above and in that it protects against spells level 1-4 rather than 1-3.',0,0),(234,'Grasping Hand','Magic-User',7,'Arcane Evocation','Evocation','10 ft/level','1 round/level','magical hand','V, S, M','7 segments','none','This spell is a more powerful evocation of the forceful hand spell, acting in the same manner but able to hold motionless a creature of up to 1,000 lbs or move creatures with twice the force of a forceful hand.',0,0),(235,'Guards and Wards','Magic-User',6,'Arcane Abjuration','Abjuration','0','2 hours/level','up to 2,000 sq ft/level','V, S, M','3 turns','see below','This powerful spell is primarily  used to defend the caster\'s stronghold.  The ward protects 200 square ft per level. The warded area can be as much as 20 ft high and shaped as the caster desires. The magic user can ward several stories of a stronghold by dividing  the area among them; he or she must be somewhere within the area to be warded to cast the spell.  The spell creates the following magical effects within the warded area:\r\n\r\nfog:  Fog fills all corridors, obscuring all sight, including infravision, beyond 10 ft.\r\n\r\nWizard locks:  All doors in the warded area are wizard locked.\r\n\r\nWebs:  Webs fill all stairs from top to bottom. These strands are identical to those created by the web spell, except that they regrow in 10 minutes if they are burned or torn away while the guards and wards spell lasts.\r\n\r\nconfusion:  Where there are choices in direction',0,0),(236,'Gust of Wind','Magic-User',3,'Arcane Transmutation/Alteration','Transmutation/Alteration','0','1 segment','10 ft wide path, 10 ft long/level','V, S, M','3 segments','none','Hand outstretched in the final somatic gesture of this spell, the magic user summons forth a powerful blast of air, forceful enough to blow out unprotected flames smaller than a campfire. Flames the size of a campfire or greater will flare back as far as 1d6 ft, and even shielded flames have a high chance of being extinguished  (5% per level). The wind is strong enough to hurl a small flying creature backwards by 1d6 x 10 ft, and will hold medium-sized creatures back from moving.',0,0),(237,'Hallucinatory Terrain','Magic-User',4,'Arcane Illusion/Phantasm','Illusion/Phantasm','20 ft/level','see below','10 x 10 ft sq/level','V, S, M','1 turn','none','This spell masks the true appearance of an area, making it appear as something else. A road can be made to appear as a river, a forest can be made to appear as a ravine, etc. The spell\'s effect remains until some intelligent being touches the area (or until it is dispelled). The spell is particularly useful for hiding pits or making cliff edges seem to extend more than they actually do, but it has many other useful applications for the creative player.',0,0),(238,'Haste','Magic-User',3,'Arcane Transmutation/Alteration','Transmutation/Alteration','60 ft','3 rounds + 1 round/level','1 creature/level in a 40 x 40 ft area','V, S, M','3 segments','none (willing targets only)','This spell imbues creatures in the targeted area with preternatural speed, allowing them to move and attack at twice the normal rate. The rate of spell casting cannot be increased. Within  the area of effect, creatures closest to the caster will be affected first by the spell if the caster\'s level is not sufficient to affect all of the creatures in the area. The spell ages the creatures upon which it is cast by 2 years.',0,0),(239,'Hold Monster','Magic-User',5,'Arcane Enchantment/Charm','Enchantment/Charm','5 ft/level','1 round/level','1-4 creatures','V, S, M','5 segments','negates','A hold monster spell completely immobilizes up to four creatures of any kind for the spell\'s duration. The magic user decides how many creatures he or she will target with the spell: if there is only one target, the saving throw is made at -3; if two, each makes the saving throw at -1; and if the magic user seeks to hold three or four enemies, each makes its saving throw with no penalty. If a magic item or spell operates partially to negate the effects of paralysis, failure on the saving throw will have the effect of a slow spell rather than completely immobilizing the target. Creatures held by this spell may be killed or bound at a rate of one per round, or, if the attacker chooses, may be attacked at twice the normal rate with an automatic hit, for maximum damage.',0,0),(240,'Hold Person','Magic-User',3,'Arcane Enchantment/Charm','Enchantment/Charm','120 ft','2 rounds/level','see below','V','3 segments','negates','This spell has the same effect as the clerical spell hold person: to immobilize foes and render them helpless. However, the magic user\'s version of the spell is somewhat more flexible in terms of the caster\'s options. A hold person spell completely immobilizes up to four man-sized or smaller persons for the spell\'s duration. The magic user decides how many of his or her foes he or she will target with the spell: if there is only one target, the saving throw is made at -3, if two, each makes the saving throw at -1, and if the magic user seeks to hold three or four enemies, each makes his or her saving throw with no penalty. Creatures affected by this spell would include humans, demi-humans and humanoids. Ultimately, it is in the discretion  of the GM to decide if a creature is considered a \"person\" for the purposes of this spell. If a magic item or spell operates to partially negate the effects of paralysis, failure on the saving throw will have the effect of a slow spell rather than completely immobilising the target. Persons held by this spell may be killed or bound at a rate of one per round, or, if the attacker chooses, may be attacked at twice the normal rate with an automatic hit, for maximum damage.',0,0),(241,'Hold Portal','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','20 ft/level','1 round/level','one portal up to 80 sq ft/level','V','1 segment','none','This quickly shouted spell holds fast a door or similar aperture as if it were securely locked. The portal must be something that normally opens and closes, such as a door, gate, valve, or portcullis, and it must be closed for the spell to function. A magically held portal can be battered apart, but will not open normally until the spell\'s duration expires. This is not a particularly powerful spell; any being not native to the material planes (such as a demon) will ignore its effects, as will a magic user four or more levels higher than the caster. The spell may also be negated by means of a knock or dispel magic.',0,0),(242,'Ice Storm','Magic-User',4,'Arcane Evocation','Evocation','10 ft/level','1 round','10 x 10 ft/level','V, S, M','4 segments','none','The caster may evoke one of two different forms of ice storm with this spell: a hailstorm or a sleet storm. The hailstorm is a vicious barrage of huge hailstones that pound into a 40 ft x 40 ft area, throwing up bits of shrapnel-like ice fragments as the hail shatters. Any creature within the area suffers 3d10 hit points of damage with no saving throw. The sleet storm is a maelstrom of frozen rain in an 80 ft x 80 ft area, blinding all creatures in the area of effect and making the footing  so slippery that all movement is cut by 50%. There is also a 50% probability that any creature attempting to move while in the sleet storm will slip and fall prone.',0,0),(243,'Identify','Magic-User',1,'Arcane Divination','Divination','touch','1 segment/level','one item','V, S, M','1 turn','see below','This expensive and unreliable  spell allows the magic user to discern the magical properties  of an item. The magic user must hold or wear the item as intended for use (thereby placing himself at risk of a cursed item). For every segment of the spell\'s duration, the magic user has a 15% +5%/level of gaining an insight into the nature of the item\'s enchantment. Insights include magical effects (and the corresponding command word) and number of charges (plus or minus 25% of the actual number). The exact bonus (or penalty) of a weapon is not revealed to the player, unless the GM chooses to do so for convenience; the character, of course, would not think of a magic sword as being \"+1\" or \"+3,\" just as \"enchanted\" or \"powerfully enchanted,\" and the spell reveals information in these terms. The spell must be cast within 1 hour/level of the time a magic item first comes near the caster, or the magic user\'s own aura will have blended too much into the item\'s aura, contaminating his ability to read it. Upon casting the spell, the magic user temporarily loses 8 points of constitution, and regains them by resting for one hour per recovered point. The material component for the spell is a pearl worth 100 gp.',0,0),(244,'Imprisonment','Magic-User',9,'Arcane Abjuration','Abjuration','touch','permanent','one creature','V, S','9 segments','none','The power of this spell hurls the victim deep beneath the earth, placing it into a state of suspended animation for eternity, entombed within  a cyst of rock. The only way to free an imprisoned creature is with the reverse of the spell, and the caster must know the name of the prisoner together with enough detail to clearly identify him or her. A creature freed from imprisonment appears at the exact spot where the imprisonment took place. When casting the spell\'s reverse, if the caster is not specific enough about the imprisoned creature\'s identity the spell will normally fail; but there is also a chance it will free the intended creature together with several other imprisoned victims from other places in the ground',1,0),(245,'Incendiary Cloud','Magic-User',8,'Arcane Evocation','Evocation','30 ft','1d6+4 rounds','cloud, 10 ft high, 20 ft radius','V, S, M','2 segments','half','The incendiary cloud begins as a choking cloud of thick smoke, with the attributes of a pyrotechnics spell\'s smoke cloud, billowing from an existing fire source as per the pyrotechnics spell. The cloud has a radius of 20 ft and is 10 ft high. On the third round of the cloud\'s existence, it bursts into hot, magical flame. A saving throw for half damage is permitted to every creature in the cloud for each round of exposure to the flames. In the first round of the flare, the blazing cloud inflicts one hit point of damage for every two levels of the caster. In the second round of the flare, the heat increases to inflict 1 hit point per level, and in the third round of the blaze, damage falls again to one point per two levels. After three rounds, the cloud burns out, and for any further  duration  it retains only the properties of pyrotechnic smoke.',0,0),(246,'Infravision','Magic-User',3,'Arcane Transmutation/Alteration','Transmutation/Alteration','touch','12 turns +6 turns/level','one creature','V, S, M','1 round','none','This spell allows the magic user to confer the ability to see in the dark, perceiving variations of heat in the infrared spectrum. The range of this vision is 60 ft. Lamps and other light sources tend to spoil the effects of infravision.  Infravision  does not perceive invisibility any more than normal vision.',0,0),(247,'Instant Summons','Magic-User',7,'Arcane Conjuration/Summoning','Conjuration/Summoning','see below','instantaneous','one object','V, S, M','1 segment','none','This spell calls a specific, desired object into the caster\'s hand from wherever it might be. The object must be prepared ahead of time, with the first part of the spell being cast upon it at that time',0,0),(248,'Interposing Hand','Magic-User',5,'Arcane Evocation','Evocation','10 ft/level','1 round/level','magical disembodied hand','V, S, M','5 segments','none','This spell creates a magical hand with the same number of hit points as the caster. The magic user can cause the hand to be as small as his or her own, or as large as a shield. The caster selects a foe, and the hand will place itself between the magic user and that particular enemy, moving so rapidly that it cannot be avoided. It is strong enough to hold back any creature weighing 200 lbs or less and will slow heavier opponents to half movement. The movement rates of opponents of truly massive size (such as dragons) will be adjudicated by the GM, being slowed to a quarter movement rate or pushing the hand aside entirely.',0,0),(249,'Invisibility','Magic-User',2,'Arcane Illusion/Phantasm','Illusion/Phantasm','touch','see below','one creature','V, S, M','2 segments','none','When the words of this spell are completed, the recipient and all he or she carries fade from sight, becoming invisible. Even infravision cannot detect an invisible creature. The spell remains in effect until the invisible creature attacks someone, the caster ends the spell, or the magic is dispelled. Note that the spell does not make the recipient any more quiet than normal, nor does it eliminate scents. The invisible person can see him or herself, but the caster (unless they are one and the same) cannot. The spell cannot be cast upon an unwilling subject.',0,0),(250,'Invisibility (10 ft radius)','Magic-User',3,'Arcane Illusion/Phantasm','Illusion/Phantasm','touch','see below','all creatures within a 10 ft radius','V, S, M','3 segments','none (willing targets only)','This spell operates as does the invisibility spell, but affects all creatures within 10 ft of the recipient at the time the final words of the spell are uttered. If the creature upon which the spell was cast makes an attack, the attack will negate the invisibility of all the others. However, if one of the creatures affected by the spell\'s radius (not the direct recipient)  attacks, the invisibility  only of that one creature is negated thereby. In order to remain invisible, those who were made invisible by virtue of the spell\'s radius must remain within  10 ft of the creature upon whom the spell is centered. All creatures affected can see each other.',0,0),(251,'Invisible Stalker','Magic-User',6,'Arcane Conjuration/Summoning','Conjuration/Summoning','10 ft','see below','see below','V, S, M','1 round','none','This spell summons an invisible stalker (see Chapter V in the OSRIC rule book). The stalker will perform one task as commanded by the caster, but resents its slavery and will always seek to misinterpret a command if it is worded ambiguously.',0,0),(252,'Irresistible Dance','Magic-User',8,'Arcane Enchantment/Charm','Enchantment/Charm','touch','1d4 +1 rounds','one creature','V','5 segments','none','The creature touched (successful to hit roll) flies into an uncontrollable, twitching tarantella, dancing wildly. The creature\'s armor class is penalized by -4, and it will fail any and all saving throws during the spell\'s duration. It cannot act in any way, or gain benefit from a shield.',0,0),(253,'Jump','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','touch','see below','one creature','V, S, M','1 segment','none','This spell allows the subject to make one or more prodigious leaps, one additional leap for each three levels above 1. Thus, at a level of 4, the spell permits a second leap, with additional leaps at level 7, 10, 13, etc. The recipient of the spell may bound forward 30 ft, or may leap backward or straight up for a distance of 10 ft. The leap is almost perfectly straight, with no arc.',0,0),(254,'Knock','Magic-User',2,'Arcane Transmutation/Alteration','Transmutation/Alteration','60 ft','see below','10 sq ft/level','V','1 segment','none','The powerful magic words of a knock spell open doors that are stuck, barred, locked, or even wizard locked. Chains (even those that are welded) and chests will also spring open under this spell. Doors that operate by gravity, such as portcullises, will not be opened by means of the spell. If a door is secured by a number of devices, only two will be opened by the spell; a triple-locked door is proof against a single casting of the enchantment.',0,0),(255,'Legend Lore','Magic-User',6,'Arcane Divination','Divination','caster','see below','see below','V, S, M','see below','none','This spell, when cast, gathers mystical echoes of legend and rumor about a specific person, place, or object. These inchoate rhymes, whispers, and memories form in the caster\'s mind until he can finally piece them together  into meaningful information. The spell\'s power is far greater if the item is actually at hand when the spell is cast, for it can then be used as a focus for the gathering of echoes; casting time under these circumstances will be 1d4 turns. If the item (or place) is not at hand, but some detailed information can be woven into the casting of the spell as a focus for the gathering of legend-echoes, the casting time will be 1d10 days. If all that the caster knows about the object or place is rumor, the casting time will be\r\n2d6 weeks. While casting the spell, the caster may not engage in any other activity other than short breaks to eat and sleep.\r\n\r\nWhen completed, the spell will reveal the location of any legendary material about the object (or person, or place), and if the spell is cast in the presence of the place, person, or object the spell will invariably gather the legendary lore together  into a piece of true information about it. This information, coming as it does from mystical echoes, will take the form of a riddle, rhyme, or other puzzle. In order to cast the spell an item of some value',0,0),(256,'Levitate','Magic-User',2,'Arcane Transmutation/Alteration','Transmutation/Alteration','20 ft/level','1 turn/level','caster or one creature','V, S, M','2 segments','negates','This spell allows the magic user to levitate him or herself or another person, to a maximum weight of 100 lbs/level. The magic user can move vertically up or down at a rate of 20 ft per round, and can levitate another at a rate of 10 ft per round. The spell may be cast upon an unwilling enemy, but in this case the intended  target is entitled  to a saving throw. The spell does not allow any sort of horizontal movement (aerial agility level I see Chapter III of the OSRIC rule book), but it is possible for a levitated person to pull him or herself along if there is something upon which to gain purchase, such as a wall.',0,0),(257,'Light','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','60 ft','1 turn/level','20 ft radius globe','V, S','1 segment','none','Other than as noted above, this spell is identical to the clerical spell light.',0,42),(258,'Lightning Bolt','Magic-User',3,'Arcane Evocation','Evocation','40 ft +10 ft/level','instantaneous','see below','V, S, M','3 segments','half','As the caster completes this spell, he or she unleashes a bolt of lightning from the spell\'s point of origin, which may be as far away from the caster as the spell\'s maximum range. The bolt extends in a straight line from the caster beginning, at whatever point along the spell\'s range the caster desires, and may extend beyond the spell\'s range. The bolt deals 1d6 damage per level to all creatures standing in the bolt\'s area of effect. Creatures that make successful saving throws suffer half damage. The area of effect may be either a branching, forking maelstrom of electricity 10 ft wide and 40 ft long, or it may be a concentrated blast 5 ft wide and 80 ft long. The length of the bolt itself is not affected by the caster\'s level, only the range at which the caster may cause the bolt to originate.\r\n\r\nAll items hit by the full force of the bolt must make item saving throws or be destroyed. The force of the bolt is often sufficient to blast doors into smouldering ruin. If the bolt strikes an object that does not conduct electricity,  such as a stone wall, it will be deflected backward toward the caster (potentially inflicting a second shock upon those in the target area). Note that the length of a deflected bolt is not increased; the bolt will only rebound for the distance remaining in its original area of effect.',0,0),(259,'Limitied Wish','Magic-User',7,'Arcane Conjuration/Summoning','Conjuration/Summoning','unlimited','instantaneous','see below','V','see below','see below','Limited wish is a powerful spell, allowing the caster to reshape reality in accordance with his or her desire, but only to a limited degree. The spell may be used to grant minor wishes (undoing curses, granting small quantities of gold, duplicating the effects of lower level spells, etc.) The effects of the spell will be permanent for most minor requests, particularly  when used to duplicate a lower-level spell that has a permanent or instantaneous duration.\r\n\r\nHowever, a limited wish is not powerful enough to make major changes in reality.  It cannot bring the dead back to life, grant a level, or permanently change ability scores. In many cases, the GM will be called upon to determine whether the caster\'s wish is within the power of a limited wish spell or whether  the results of the request will suffer from flaws due to the spell\'s limitations.  Flaws would include limited  durations or partial results. The guidelines set forth above should give the GM some assistance in making such determinations.\r\n\r\nIn the case of unreasonable wishes, the GM may decide to follow the wording  of the spell precisely but pervert the intent, limit the duration  of the spell to a very limited  time (perhaps mere seconds!) or simply rule that the whole spell fails.\r\n\r\nThe guideline  here is that wishes are granted by someone or something, which may or may not be kindly disposed to the player characters. The more greedy or selfish a wish, the greater the chance that a mischievous or actually evil power will take the opportunity to teach this upstart mortal a lesson.',0,0),(260,'Locate Object','Magic-User',2,'Arcane Divination','Divination','20 ft/level','1 round/level','see below','V, S, M','2 segments','none','Other than as noted above, this spell is identical to the clerical spell locate object.',0,43),(261,'Lower Water','Magic-User',6,'Arcane Transmutation/Alteration','Transmutation/Alteration','80 ft','5 rounds/level','5 x 5 sq ft area/level','V, S, M','1 turn','none','Except as may be noted above, this spell is identical to the clerical spell lower water. The spell\'s reverse can raise water no more than 5 ft/level.',0,44),(262,'Mage\'s Faithful Hound','Magic-User',5,'Arcane Conjuration/Summoning','Conjuration/Summoning','10 ft','2 rounds/level','see below','V, S, M','5 segments','none','This spell summons an invisible watchdog to guard an area. The hound is invisible to all but the caster, who may order it to keep watch over a particular area. The area must be close to the caster, however, for if the caster is more than 30 ft from the area the hound guards, it will return to the spirit realm. The hound can detect virtually any creature that enters the area: it can detect invisibility (which includes creatures on the astral and ethereal planes), can see creatures that are moving between dimensions, and can detect virtually any other method that might be employed to sneak into an area. If any creature larger than a cat or small dog enters the area, the hound will begin baying with its echoing, supernatural bark. Moreover, it will seek to attack intruders from behind (it does not make frontal assaults) and can attack as a monster of 10\r\nHD for 3d6 damage, even if the opponent requires up to a +3 magical weapon to be hit. The hound cannot be harmed by any means other than by dispelling it.',0,0),(263,'Mage\'s Sword','Magic-User',7,'Arcane Evocation','Evocation','30 ft','1 round/level','summoned sword','V, S, M','7 segments','none','The caster evokes a magical sword into being and can wield it by exerting his or her will. While doing  so, he or she cannot cast spells, use magic items, or move, although the spell does not end if the magic user\'s concentration is broken; the sword simply does not attack during that round. The sword attacks as a fighter one-half the magic user\'s level (and always hits on a natural 19 or 20), and it can hit creatures that can ordinarily be hit only with magic weapons. The damage caused by the sword is considerable; it inflicts 5d4 hp against size S and M creatures, or 5d6 against larger creatures. The sword can be dispelled by dispel magic. The material components for the spell cost 500 gp or more.',0,0),(264,'Magic Aura','Magic-User',1,'Arcane Illusion/Phantasm','Illusion/Phantasm','touch','1 day/level','see below','V, S, M','1 round','see below','This spell creates a false magical aura around a single object of not more than five lbs per level. A detect magic spell will incorrectly perceive the item as magical, but if it is actually handled by the caster of the detect magic spell, he or she will be permitted a saving throw to realize that the aura is, in fact, not a true magical aura but a counterfeit.',0,0),(265,'Magic Jar','Magic-User',5,'Arcane Possession','Possession','10 ft/level','see below','one creature','V, S, M','1 round','negates','This risky spell allows the caster to transfer his or her mind into that of another creature, trapping the other creature\'s soul in a gem (of not less than 100 gp value) that is the material component of the spell and becomes the magic jar. To accomplish the transfer of souls, the magic user must trap his or her own life essence within  the jar prior to the transfer. If the transfer fails (e.g., if the targeted creature makes a successful saving throw), the caster\'s soul is trapped until it can take over a host or otherwise escape.\r\n\r\nThe caster can make successive attempts to take over the same host, but no more than one per round. The spell\'s range applies to two matters; when the magic user first transfers his or her own life essence into the jar, his or her body must be within the spell\'s range of the jar. The range also limits the distance at which the magic user\'s soul may later escape from the jar and into another body. After the caster\'s soul moves into the jar, his or her physical body becomes inert and lifeless.\r\n\r\nThe spell represents, in many ways, a contest of will between the magic user and the creature whose body he or she seeks to possess. The caster and the target creature each total their intelligence and wisdom scores (such being calculated or approximated  by the GM for a monster). This combined  score represents the character\'s mental power for purposes of the spell. The two numbers are compared, and the difference is used in two important calculations: the saving throw and the chance for escape. One third of the difference  (rounded down) is the modifier on the saving throw, a bonus if the target creature has the higher mental power, a penalty if the magic user\'s mental power is higher.\r\n\r\nIf a creature\'s soul is trapped in the magic  jar by the caster, it has a chance to escape. If it escapes, the caster\'s soul is returned  to the magic  jar. If the difference  in mental power between the caster and the possessed creature is 4 or less in favor of the caster, or is in favor of the possessed creature, the creature can attempt a new saving throw every round. If the difference  is from 5 to 8 in the caster\'s favor, one saving throw is permitted per turn. If the difference  is 9 to 12 in the caster\'s favor, the saving throw is made once per day, and if the caster\'s mental power exceeds that of the target creature by 13+, the saving throw can only be made once per week.\r\n\r\nWhile the caster is in the magic jar waiting to possess another body, he or she can sense creatures beyond the jar, but not their nature. The jar may be moved from its original location, but not, obviously, by the caster. When the caster possesses another body, he or she gains complete control  of its movement and acquires any memories that the body might reflexively recall (how to fly, fight with claws, use innate magical powers, etc). He or she does not gain any knowledge from the creature\'s mind, such as languages known or the location of a lair, for the mind is trapped in the magic jar. The caster retains his or her own mind while possessing the other body, so if the body possesses the correct physical attributes the caster can continue to cast his or her spells from within the new body.\r\n',0,0),(266,'Magic Missile','Magic-User',1,'Arcane Evocation','Evocation','60 ft +10 ft/level','instantaneous','1+ creatures in a 10 x 10 ft area','V, S','1 segment','none','When this spell is cast, missiles of magical energy dart forth from the caster\'s fingertips, striking unerringly at his or her intended  target(s), even if the target(s) are in melee or are partially concealed. The missiles inflict 1d4+1 points of damage each. For every two levels beyond first, the caster gains an additional missile; thus, a first-level magic user can cast one missile, a third-level caster may cast 2, a fifth-level caster may cast 3, and so on.',0,0),(267,'Magic Mouth','Magic-User',2,'Arcane Transmutation/Alteration','Transmutation/Alteration','see below','permanent (until triggered)','one object','V, S, M','2 segments','none','This spell is cast upon an object, so that when a set of particular conditions are met, a mouth will appear in the object and speak a specific message. The length of the message cannot exceed 25 words. The magic user can set any condition for the appearance of the magic mouth, but the caster\'s power limits the range at which the mouth can detect the triggering events. The mouth can \"perceive\" events at a range of 5 ft/level, but cannot detect invisible creatures. It has no perceptions other than visual, although it does not actually see. Obviously, a player cannot try to phrase conditions using game terms such as \"hit dice,\" \"class,\" \"level,\" etc. but must use terms that would be familiar to the character.',0,0),(268,'Mass Charm','Magic-User',8,'Arcane Enchantment/Charm','Enchantment/Charm','5 ft/level','see below','see below','V','8 segments','negates','This spell functions as does charm  monster, but affects more than one creature. Total hit dice limits the number of creatures affected; the caster cannot affect a total number of hit dice more than twice his or her level. All of the target creatures must be within a 30 x 30 ft area.',0,0),(269,'Mass Invisibility','Magic-User',7,'Arcane Illusion/Phantasm','Illusion/Phantasm','10 ft/level','see below','30 x 30 ft radius','V, S, M','7 segments','none','This spell acts in the same manner as an invisibility spell, but has an effective radius of 30 x 30 ft, possibly hiding as many as 300 medium-sized creatures if they are packed in close and do not jostle one another.',0,0),(270,'Massmorph','Magic-User',4,'Arcane Illusion/Phantasm','Illusion/Phantasm','10 ft/level','see below','10 x 10 sq ft/level','V, S, M','1 turn','none (willing creatures only)','This spell causes creatures of man size or smaller to appear like an innocent grove of trees to any observers. Up to 10 creatures may be enchanted in this manner. The illusion is so powerful that it is maintained even if the massmorphed creatures are touched. The \"tree\'s\" reaction to being stabbed or hacked at is fairly likely to indicate that it is no normal tree, of course, although the illusion  is not actually dispelled by a successful attack. The illusion  persists until the caster dies or dismisses it (or it is dispelled).',0,0),(271,'Maze','Magic-User',8,'Arcane Conjuration/Summoning','Conjuration/Summoning','5 ft/level','see below','one creature','V, S','3 segments','none','The targeted creature is trapped by this spell into an inter-dimensional reality similar to that created by the second level spell rope trick. This wormhole has an entrance, which closes immediately after the target is trapped, and an exit, which is difficult to find in the branching, twisting maze of the dimensional labyrinth. A creature\'s intelligence determines the amount of time required  to find the way out and emerge back into the material plane.\r\n\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		<b>Intelligence</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		<b>Time Required to Escape</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		2 or less</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		2d4 turns (20-80 minutes)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		3-5</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		1d4 turns (10-40 minutes)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		6-8</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		5d4 rounds (5-20 minutes)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		9-11</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		4d4 rounds (4-16 minutes)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		12-14</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		3d4 rounds (3-12 minutes)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		15-17</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		2d4 rounds (2-8 minutes)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		18+</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		1d4 rounds (1-4 minutes)</td>\r\n	</tr>\r\n</table></div><br>',0,0),(272,'Mending','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','30 ft','instantaneous','one object','V, S, M','1 segment','none','This spell repairs small breaks or tears in an object. It can weld together  broken metallic objects, such as a chain link or a broken dagger, rejoin a broken bottle, and repair holes in leather or cloth, for example. The spell does not repair magic items in any way that would restore or affect their magical qualities.',0,0),(273,'Message','Magic-User',1,'Arcane Transmutation/Alteration','Transmutation/Alteration','60 ft + 10 ft/level','5 segments +1 segment/level','see below','V, S, M','1 segment','none','Once this spell is cast, the magic user may point to any creature in range and whisper a message that the other creature will hear. If there is time remaining, the recipient  may whisper a message in reply. Only one creature may be in contact with the caster at a time, but if time allows, the caster may make contact with more than one possible recipient. The gestures of this spell are subtle, and it is easy to conceal that the enchantment  is being cast. Note that the path between the magic user and the recipient must be a straight line and not completely blocked.',0,0),(274,'Meteor Swarm','Magic-User',9,'Arcane Evocation','Evocation','40 ft +10 ft/level','instantaneous','see below','V, S','9 segments','none or half (see below)','Meteor-like chunks of magical fire streak from the magic user\'s outstretched hand, exploding  into an inferno  of flame when they strike the intended targets. The caster may hurl four large meteors or eight small meteors. These missiles strike the first creature in their straight-line trajectories automatically, granting no saving throw and inflicting full damage. When the meteor strikes its target, the explosion of fire may catch other creatures in its radius. These creatures receive saving throws for half damage. Large meteors inflict  10d4 hp damage and explode in a radius of 15 ft. Small meteors inflict 5d4 hp damage and explode in a radius of 7',0,0),(275,'Mind Blank','Magic-User',8,'Arcane Abjuration','Abjuration','30 ft','24 hours','one creature','V, S','1 segment','none','By means of this spell, the person upon whom it is cast becomes completely  protected  from all divination and scrying magic. His or her thoughts cannot be detected in any way, he or she cannot be magically overheard when speaking, his or her soul cannot be trapped or affected, etc.',0,0),(276,'Minor Globe of Invulnerability','Magic-User',4,'Arcane Abjuration','Abjuration','0','1 round/level','5 ft radius sphere','V, S, M','4 segments','none','A globe of eldritch power forms around the magic user, hedging out all spells of third  or lower level. Spells may be cast from within  the globe. Dispel magic, if cast upon the globe, will destroy it.',0,0),(277,'Mirror Image','Magic-User',2,'Arcane Illusion/Phantasm','Illusion/Phantasm','caster','2 rounds/level','6 ft radius','V, S','2 segments','none','The mirror image spell creates 1d4 phantasmal images of the magic user, all mirroring his or her actions. The spell\'s 6ft radius also becomes slightly blurred  to sight, like the reflection of a slightly distorted mirror. The combination of these two magical phenomena makes it impossible to distinguish the images from the caster without aid of a magical nature, such as true seeing. When an opponent makes a successful hit against one of the images, the image breaks up and disappears (the others remain). If an opponent attempts to attack a magic user obscured by this spell, it is randomly determined whether  the to-hit roll is directed toward the person or one of the images. At the end of the spell\'s duration, the images fade from sight.',0,0),(278,'Mnemonic Enhancement','Magic-User',4,'Arcane Transmutation/Alteration','Transmutation/Alteration','caster','24 hours','caster','V, S, M','1 turn','none','This spell enhances the magic user\'s precision of memory, allowing him or her to retain up to three additional spell levels in his or her mind (3 first level, 1 first and one second level, or 1 third level). The spell may be used for memorization, or may be used to hold onto the memory of a spell just cast. The spell components are expensive, costing at least 100 gp, and might not be available in rural communities.',0,0),(279,'Monster Summoning I','Magic-User',3,'Arcane Conjuration/Summoning','Conjuration/Summoning','30 ft','2 rounds +1 round/level','summoned creatures','V, S, M','3 segments','none','By casting this spell, the magic user conjures up 2-8 monsters to serve him or her as allies in combat or to perform  other services. The monsters appear from thin air within 1d4 rounds of the spell\'s completed casting. If the caster is in combat, the monsters will fight on his or her behalf, attacking whatever foes he directs, or guarding him or her. For more complex tasks, the magic user must somehow have the ability to communicate these more specific commands. The GM has the ultimate discretion  as to what monsters will appear, but the general likelihood is described below:\r\n\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		<b>1d6</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		<b>Monster Summoned</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Rat, Giant</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		2</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Goblin (Dwarf)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		3</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Hobgoblin (Elf)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		4</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Kobold (Halfling)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		5</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Orc (Gnome)</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		6</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Demon, Kullule (Badger, Giant)</td>\r\n	</tr>\r\n</table></div><br>\r\n\r\nEvil casters may get the monsters in parentheses, at the GM\'s option.',0,0),(280,'Monster Summoning II','Magic-User',4,'Arcane Conjuration/Summoning','Conjuration/Summoning','40 ft','3 rounds +1 round/level','summoned creatures','V, S, M','4 segments','none','By casting this spell, the magic user conjures up 1-6 monsters to serve him or her as allies in combat or to perform  other services. The monsters appear from thin air within 1d4 rounds of the spell\'s completed casting. If the caster is in combat, the monsters will fight on his or her behalf, attacking whatever foes he directs, or guarding him or her. For more complex tasks, the magic user must somehow have the ability to communicate these more specific commands. The GM has the ultimate discretion  as to what monsters will appear, but the general likelihood is described below:\r\n\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		<b>1d6</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		<b>Monster Summoned</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Centipede, Giant</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		2</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Devil, Lemure</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		3</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Gnoll</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		4</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Stirge</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		5</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Toad, Giant</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		6</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Toglodyte</td>\r\n	</tr>\r\n</table></div><br>',0,0),(281,'Monster Summoning III','Magic-User',5,'Arcane Conjuration/Summoning','Conjuration/Summoning','50 ft','4 rounds +1 round/level','summoned creatures','V, S, M','5 segments','none','By casting this spell, the magic user conjures up 1-4 monsters to serve him or her as allies in combat or to perform  other services. The monsters appear from thin air within 1d4 rounds of the spell\'s completed casting. If the caster is in combat, the monsters will fight on his or her behalf, attacking whatever foes he directs, or guarding him or her. For more complex tasks, the magic user must somehow have the ability to communicate these more specific commands. The GM has the ultimate discretion  as to what monsters will appear, but the general likelihood is described below:\r\n\r\n<br><br><div align=\"center\"><table border=\"0\" cellpadding=\"5\" style=\"border-collapse: collapse; font-size:10pt\" width=\"80%\" bordercolorlight=\"#000000\" bordercolordark=\"#000000\">\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		<b>1d10</b></td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		<b>Monster Summoned</b></td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		1</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\">\r\n		Beetle, Giant Boring</td>\r\n	</tr>\r\n	<tr>\r\n		<td NOWRAP style=\"border-left-width: 1px; border-right-width: 1px; border-top-style: solid; border-top-width: 1px; border-bottom-style: solid; border-bottom-width: 1px\" align=\"center\">\r\n		2</td>\r\n		<td style=\"border-left-width: 1px; border-right-width: 1px; border-top-s